                rightComponent={{ icon: 'home', color: '#AB445C' }}
                containerStyle={{
                    backgroundColor: '#661327',
                    justifyContent: 'space-around',
                }}
            />
        </View>
        <View style={styles.container}>
            <View style={styles.formContainer}>
                <TextInput
                    style={styles.input}
                    placeholder='Add new entity'
                    placeholderTextColor="#aaaaaa"
